const FARM_CENTER={latitude:-31.33175,longitude:-63.30745};
function rectangleFeature(lot,lat,lng,dLat,dLng){
  return {lot_id:lot.id,name:lot.name,coordinates:[
    {latitude:lat,longitude:lng},
    {latitude:lat,longitude:lng+dLng},
    {latitude:lat-dLat,longitude:lng+dLng},
    {latitude:lat-dLat,longitude:lng}
  ]};
}
function buildProvisionalFeatures(lots){
  const cols=4, gapLat=0.0010, gapLng=0.00125, startLat=FARM_CENTER.latitude+0.0034, startLng=FARM_CENTER.longitude-0.0025;
  return lots.map((lot,i)=>{
    const row=Math.floor(i/cols),col=i%cols;
    const scale=Math.max(.75,Math.min(1.35,Number(lot.area_ha||8)/9));
    return rectangleFeature(lot,startLat-row*gapLat,startLng+col*gapLng,0.00072*scale,0.0009*scale);
  });
}
function geoJsonToFeatures(text,lots){
  const parsed=JSON.parse(text);
  const source=parsed.type==='FeatureCollection'?parsed.features:[parsed];
  const byName=new Map(lots.map(l=>[String(l.name).toLowerCase(),l]));
  return source.map((f,i)=>{
    if(!f?.geometry || !['Polygon','MultiPolygon'].includes(f.geometry.type)) throw new Error('Solo se admiten polígonos GeoJSON.');
    const ring=f.geometry.type==='Polygon'?f.geometry.coordinates[0]:f.geometry.coordinates[0][0];
    const name=String(f.properties?.name||f.properties?.lote||f.properties?.lot_name||`Lote ${i+1}`);
    const lot=byName.get(name.toLowerCase())||lots[i];
    return {lot_id:lot?.id||`import-${i}`,name:lot?.name||name,coordinates:ring.map(([longitude,latitude])=>({latitude:Number(latitude),longitude:Number(longitude)}))};
  });
}

function money(v){return new Intl.NumberFormat('es-AR',{style:'currency',currency:'ARS',maximumFractionDigits:0}).format(Number(v||0));}

function daysSince(value){if(!value)return 7; return Math.max(0,Math.floor((Date.now()-new Date(value).getTime())/86400000));}
async function safeSelect(table, companyId, order){
  try{
    let q=supabase.from(table).select('*');
    if(companyId) q=q.eq('company_id',companyId);
    if(order) q=q.order(order,{ascending:false});
    const {data,error}=await q;
    if(error) return [];
    return data||[];
  }catch{return [];}
}

export default function App(){
  const [session,setSession]=useState(null),[loading,setLoading]=useState(true);
  useEffect(()=>{supabase.auth.getSession().then(({data})=>{setSession(data.session);setLoading(false)});const {data}=supabase.auth.onAuthStateChange((_e,s)=>setSession(s));return()=>data.subscription.unsubscribe();},[]);
  if(loading)return <Centered><ActivityIndicator size="large" color={GREEN}/></Centered>;
  return session?<Main session={session}/>:<Login/>;
}

function Login(){
  const [email,setEmail]=useState('francolucianobodio@gmail.com'),[password,setPassword]=useState(''),[fullName,setFullName]=useState(''),[mode,setMode]=useState('login'),[busy,setBusy]=useState(false);
  async function submit(){
    const clean=email.trim().toLowerCase();
    if(!clean)return Alert.alert('Falta el correo');
    setBusy(true);
    try{
      if(mode==='reset'){
        const {error}=await supabase.auth.resetPasswordForEmail(clean);
        if(error)throw error;
        Alert.alert('Correo enviado','Revisá tu casilla para recuperar la contraseña.');setMode('login');
      }else if(mode==='register'){
        if(!password||password.length<6)throw new Error('La contraseña debe tener al menos 6 caracteres.');
        const {error}=await supabase.auth.signUp({email:clean,password,options:{data:{full_name:fullName.trim()||clean.split('@')[0]}}});
        if(error)throw error;
        Alert.alert('Cuenta creada','Si Supabase solicita confirmación, revisá tu correo antes de ingresar.');setMode('login');
      }else{
        if(!password)throw new Error('Falta la contraseña.');
        const {error}=await supabase.auth.signInWithPassword({email:clean,password});
        if(error)throw error;
      }
    }catch(e){Alert.alert('No se pudo continuar',e.message||'Error de autenticación');}
    setBusy(false);
  }
  const title=mode==='register'?'Crear cuenta':mode==='reset'?'Recuperar acceso':'LA MAGDALENA OS';
  return <KeyboardAvoidingView style={styles.loginBg} behavior={Platform.OS==='ios'?'padding':undefined}><ScrollView contentContainerStyle={styles.loginScroll} keyboardShouldPersistTaps="handled"><View style={styles.loginCard}><View style={styles.logo}><Text style={styles.logoText}>LM</Text></View><Text style={styles.kicker}>PLATAFORMA AGROPECUARIA</Text><Text style={styles.loginTitle}>{title}</Text><Text style={styles.muted}>{mode==='login'?'Producción, riego, precisión y servicios desde el campo.':mode==='register'?'Creá tu usuario para trabajar con establecimientos y permisos separados.':'Te enviaremos un enlace seguro para recuperar tu cuenta.'}</Text>{mode==='register'&&<><Text style={styles.label}>Nombre completo</Text><TextInput style={styles.input} value={fullName} onChangeText={setFullName} autoCapitalize="words"/></>}<Text style={styles.label}>Correo</Text><TextInput style={styles.input} value={email} onChangeText={setEmail} autoCapitalize="none" keyboardType="email-address"/>{mode!=='reset'&&<><Text style={styles.label}>Contraseña</Text><TextInput style={styles.input} value={password} onChangeText={setPassword} secureTextEntry onSubmitEditing={submit}/></>}<Pressable style={styles.primary} onPress={submit} disabled={busy}><Text style={styles.primaryText}>{busy?'Procesando…':mode==='login'?'Ingresar':mode==='register'?'Crear cuenta':'Enviar enlace'}</Text></Pressable><View style={styles.authLinks}>{mode!=='login'?<Pressable onPress={()=>setMode('login')}><Text style={styles.authLink}>Volver a ingresar</Text></Pressable>:<><Pressable onPress={()=>setMode('register')}><Text style={styles.authLink}>Crear cuenta</Text></Pressable><Pressable onPress={()=>setMode('reset')}><Text style={styles.authLink}>Olvidé mi contraseña</Text></Pressable></>}</View></View></ScrollView></KeyboardAvoidingView>;
}

function Main({session}){
  const [tab,setTab]=useState('Inicio'),[company,setCompany]=useState(COMPANY_FALLBACK),[companyId,setCompanyId]=useState(''),[companies,setCompanies]=useState([]),[membership,setMembership]=useState(null),[showAccount,setShowAccount]=useState(false),[lots,setLots]=useState([]),[clients,setClients]=useState([]),[irrigations,setIrrigations]=useState([]),[analyses,setAnalyses]=useState([]),[weather,setWeather]=useState(null),[refreshing,setRefreshing]=useState(false),[syncMode,setSyncMode]=useState('local'),[operations,setOperations]=useState([]),[mapFeatures,setMapFeatures]=useState([]);
  async function load(preferredCompanyId){
    let available=[];
    try{
      const {data:members}=await supabase.from('company_members').select('company_id,role,companies(*)').eq('user_id',session.user.id);
      available=(members||[]).map(m=>({...m.companies,member_role:m.role})).filter(Boolean);
      if(!available.length){const {data}=await supabase.from('companies').select('*').order('name');available=data||[];}
    }catch{}
    setCompanies(available);
    const c=available.find(x=>x.id===preferredCompanyId)||available.find(x=>x.id===companyId)||available[0]||COMPANY_FALLBACK;
    setCompany(c);setCompanyId(c.id||'');setMembership(c.member_role||'Administrador');
    const [cloudLots,cl,cloudIrrigations,an,cuts,trips,finance,geometries]=await Promise.all([
      safeSelect(TABLES.lots,c.id,'name'),safeSelect(TABLES.clients,c.id,'name'),safeSelect(TABLES.irrigations,c.id,'event_date'),safeSelect(TABLES.analyses,c.id,'flight_date'),
      safeSelect('alfalfa_cuts',c.id,'cut_date'),safeSelect('transport_trips',c.id,'trip_date'),safeSelect('financial_movements',c.id,'movement_date'),safeSelect('lot_geometries',c.id,'updated_at')
    ]);
    let localLots=[],localIrrigations=[],localOperations=[],localMap=[];
    try{localLots=JSON.parse(globalThis.localStorage.getItem(LOCAL_LOTS_KEY)||'[]');localIrrigations=JSON.parse(globalThis.localStorage.getItem(LOCAL_IRRIGATION_KEY)||'[]');localOperations=JSON.parse(globalThis.localStorage.getItem(LOCAL_OPERATIONS_KEY)||'[]');localMap=JSON.parse(globalThis.localStorage.getItem(LOCAL_MAP_KEY)||'[]')}catch{}
    const baseLots=cloudLots.length?cloudLots:(localLots.length?localLots:DEMO_LOTS);
    const effectiveLots=baseLots.map((lot,index)=>({
      ...lot,
      area_ha:Number(REAL_FARM_FEATURES[index]?.area_ha||lot.area_ha||lot.hectares||0),
      hectares:Number(REAL_FARM_FEATURES[index]?.area_ha||lot.hectares||lot.area_ha||0)
    }));
    const effectiveIrrigations=cloudIrrigations.length?cloudIrrigations:localIrrigations;
    const cloudOperations=[
      ...cuts.map(x=>({...x,type:'Alfalfa',quantity:Number(x.bales||x.rolls||0)})),
      ...trips.map(x=>({...x,type:'Scania'})),
      ...finance.map(x=>({...x,type:'Economía'}))
    ];
    let effectiveMap=localMap.length?localMap:REAL_FARM_FEATURES;
    if(geometries.length){
      const parsed=geometries.flatMap((g,i)=>{try{return geoJsonToFeatures(g.geojson,effectiveLots).map((f,j)=>({...f,lot_id:g.lot_id||f.lot_id,name:effectiveLots.find(l=>l.id===g.lot_id)?.name||f.name||`Válvula ${i+j+1}`}))}catch{return[]}});
      if(parsed.length)effectiveMap=parsed;
    }
    setLots(effectiveLots);setClients(cl);setIrrigations(effectiveIrrigations);setAnalyses(an);setOperations(cloudOperations.length?cloudOperations:localOperations);setMapFeatures(effectiveMap);setSyncMode(cloudLots.length?'cloud':'local');
    if(!localLots.length)try{globalThis.localStorage.setItem(LOCAL_LOTS_KEY,JSON.stringify(effectiveLots))}catch{}
    try{const r=await fetch('https://api.open-meteo.com/v1/forecast?latitude=-31.332065&longitude=-63.311986&current=temperature_2m,relative_humidity_2m,wind_speed_10m&daily=precipitation_sum,et0_fao_evapotranspiration&timezone=America%2FArgentina%2FCordoba');setWeather(await r.json());}catch{}
  }
  useEffect(()=>{load()},[]);
  async function refresh(){setRefreshing(true);await load(companyId);setRefreshing(false)}
  const latestAnalysis=id=>analyses.find(a=>a.lot_id===id);
  const saveOperations=next=>{setOperations(next);try{globalThis.localStorage.setItem(LOCAL_OPERATIONS_KEY,JSON.stringify(next))}catch{}};
  const saveMap=next=>{setMapFeatures(next);try{globalThis.localStorage.setItem(LOCAL_MAP_KEY,JSON.stringify(next))}catch{}};
  const content={Inicio:<Dashboard {...{company,lots,clients,weather,latestAnalysis,setTab,syncMode,operations,membership}}/>,Mapa:<FarmMap lots={lots} features={mapFeatures} onChange={saveMap} onLotsChange={setLots}/>,Lotes:<Lots lots={lots} companyId={companyId} latestAnalysis={latestAnalysis} onLotsChange={setLots} onIrrigationsChange={setIrrigations} syncMode={syncMode} setSyncMode={setSyncMode}/>,Riego:<Irrigation lots={lots} irrigations={irrigations} weather={weather}/>,Clima:<Weather weather={weather}/>,Gestión:<Operations lots={lots} clients={clients} operations={operations} onChange={saveOperations}/>} [tab];
  return <SafeAreaView style={styles.app}><StatusBar barStyle="dark-content"/><View style={styles.header}><View><Text style={styles.kicker}>LA MAGDALENA OS · 1.2.2</Text><Text style={styles.headerTitle}>{tab}</Text><Text style={styles.companyLine}>{company?.name||'La Magdalena'} · {membership||'Usuario'}</Text></View><Pressable style={styles.accountButton} onPress={()=>setShowAccount(true)}><Text style={styles.accountButtonText}>{String(session.user.email||'U').slice(0,1).toUpperCase()}</Text></Pressable></View><ScrollView style={styles.content} refreshControl={<RefreshControl refreshing={refreshing} onRefresh={refresh} tintColor={GREEN}/>} contentContainerStyle={{paddingBottom:100}}>{content}</ScrollView><View style={styles.tabbar}>{['Inicio','Mapa','Lotes','Riego','Gestión'].map(t=><Pressable key={t} style={styles.tab} onPress={()=>setTab(t)}><Text style={[styles.tabIcon,tab===t&&styles.tabActive]}>{({Inicio:'⌂',Mapa:'⌖',Lotes:'▱',Riego:'💧',Gestión:'▦'})[t]}</Text><Text style={[styles.tabText,tab===t&&styles.tabActive]}>{t}</Text></Pressable>)}</View><AccountCenter visible={showAccount} onClose={()=>setShowAccount(false)} session={session} companies={companies} companyId={companyId} onSelect={id=>{setShowAccount(false);load(id)}} membership={membership}/></SafeAreaView>;
}

function AccountCenter({visible,onClose,session,companies,companyId,onSelect,membership}){
  return <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}><View style={styles.modalOverlay}><View style={styles.accountSheet}><View style={styles.sheetHandle}/><Text style={styles.kicker}>CUENTA Y EMPRESA</Text><Text style={styles.sheetTitle}>Mi perfil</Text><Row label="Correo" value={session.user.email||'—'}/><Row label="Rol actual" value={membership||'Usuario'}/><Text style={[styles.cardTitle,{marginTop:20}]}>Establecimientos</Text>{companies.length?companies.map(c=><Pressable key={c.id} style={[styles.companyOption,c.id===companyId&&styles.companyOptionActive]} onPress={()=>onSelect(c.id)}><View><Text style={[styles.itemTitle,c.id===companyId&&{color:'#fff'}]}>{c.name||'Establecimiento'}</Text><Text style={[styles.muted,c.id===companyId&&{color:'#dfeee7'}]}>{c.location||c.member_role||'Sin ubicación'}</Text></View><Text style={[styles.chevron,c.id===companyId&&{color:'#fff'}]}>›</Text></Pressable>):<View style={styles.infoBox}><Text style={styles.infoBoxTitle}>Modo local</Text><Text style={styles.muted}>Ejecutá CONFIGURAR_SUPABASE_V22.sql para crear la empresa, membresías y permisos reales.</Text></View>}<Pressable style={styles.secondaryButton} onPress={onClose}><Text style={styles.secondaryButtonText}>Cerrar</Text></Pressable><Pressable style={styles.dangerButton} onPress={()=>supabase.auth.signOut()}><Text style={styles.dangerButtonText}>Cerrar sesión</Text></Pressable></View></View></Modal>
}

function Dashboard({company,lots,clients,weather,latestAnalysis,setTab,syncMode,operations,membership}){
  const alfalfa=lots.filter(l=>String(l.crop||l.cultivo||'').toLowerCase().includes('alfalfa')).reduce((s,l)=>s+Number(l.area_ha||l.hectares||0),0);
  const alerts=lots.filter(l=>Number(latestAnalysis(l.id)?.ndvi_avg||1)<.62).length;
  const cur=weather?.current;
  const rolls=operations.filter(x=>x.type==='Alfalfa').reduce((a,x)=>a+Number(x.quantity||0),0);
  const trips=operations.filter(x=>x.type==='Scania').length;
  const lowStock=operations.filter(x=>x.type==='Inventario'&&Number(x.stock||0)<=Number(x.minimum||0)).length;
  const result=operations.filter(x=>x.type==='Scania'||x.type==='Economía').reduce((a,x)=>a+Number(x.income||0)-Number(x.cost||0),0);
  return <><View style={styles.hero}><Text style={styles.heroKicker}>CENTRO DE CONTROL</Text><Text style={styles.heroTitle}>Buenas tardes, Franco</Text><Text style={styles.heroText}>{company?.name||'La Magdalena'} · {company?.location||'Santiago Temple, Córdoba'}</Text>{cur&&<Text style={styles.weatherLine}>🌤 {cur.temperature_2m} °C · viento {cur.wind_speed_10m} km/h</Text>}</View><View style={styles.grid}><Metric label="LOTES" value={lots.length||13} sub="registrados"/><Metric label="ALFALFA" value={`${Number(alfalfa || 88).toFixed(2).replace('.', ',')} ha`} sub="superficie"/><Metric label="ALERTAS" value={alerts} sub="NDVI / revisar"/><Metric label="ROLLOS" value={rolls} sub="registrados"/><Metric label="VIAJES" value={trips} sub="Scania"/><Metric label="STOCK BAJO" value={lowStock} sub="productos"/><Metric label="RESULTADO" value={money(result)} sub="registrado"/></View><Card title="Acciones rápidas"><View style={styles.quickGrid}><Quick text="Ver lotes" onPress={()=>setTab('Lotes')}/><Quick text="Recomendación de riego" onPress={()=>setTab('Riego')}/><Quick text="Consultar clima" onPress={()=>setTab('Clima')}/><Quick text="Producción y equipos" onPress={()=>setTab('Gestión')}/></View></Card><Card title="Estado del sistema"><Row label="Guardado" value={syncMode==='cloud'?'Supabase + iPhone':'iPhone (Supabase pendiente)'}/><Row label="Empresa" value={company?.name||'La Magdalena'}/><Row label="Rol" value={membership||'Usuario'}/><Row label="Aplicación" value="iOS + Web"/></Card></>;
}

function FarmMap({lots,features,onChange,onLotsChange}){
  const mapRef=useRef(null);
  const [selected,setSelected]=useState(null),[showImport,setShowImport]=useState(false),[geoText,setGeoText]=useState('');
  const [mapType,setMapType]=useState('satellite'),[showLabels,setShowLabels]=useState(true),[busy,setBusy]=useState(false);
  const selectedLot=selected?lots.find(l=>l.id===selected.lot_id):null;
  const totalArea=features.reduce((sum,f)=>sum+Number(f.area_ha||0),0);
  function fitFarm(){
    const coords=features.flatMap(f=>f.coordinates||[]);
    if(coords.length&&mapRef.current)mapRef.current.fitToCoordinates(coords,{edgePadding:{top:45,right:35,bottom:45,left:35},animated:true});
  }
  useEffect(()=>{const t=setTimeout(fitFarm,350);return()=>clearTimeout(t)},[features.length]);
  function importGeo(){
    try{
      const parsed=geoJsonToFeatures(geoText,lots);
      if(!parsed.length)throw new Error('No se encontraron polígonos.');
      onChange(parsed);setShowImport(false);setGeoText('');Alert.alert('Mapa importado',`${parsed.length} polígonos guardados en el iPhone.`);
    }catch(e){Alert.alert('No se pudo importar',e.message||'GeoJSON inválido');}
  }
  function resetMap(){Alert.alert('Restablecer mapa','Se volverá al mapa real original de las 13 válvulas.',[{text:'Cancelar',style:'cancel'},{text:'Restablecer',style:'destructive',onPress:()=>onChange(REAL_FARM_FEATURES)}]);}
  function colorFor(f){
    const lot=lots.find(l=>l.id===f.lot_id), crop=String(lot?.crop||'').toLowerCase(), ndvi=Number(lot?.ndvi||0);
    if(ndvi>0&&ndvi<.65)return {stroke:'#ff9a70',fill:'rgba(204,63,45,.48)'};
    if(crop.includes('trigo'))return {stroke:'#ffd866',fill:'rgba(164,117,18,.42)'};
    return {stroke:'#c9ef6b',fill:'rgba(7,81,61,.48)'};
  }
  async function quickRegister(type){
    if(!selectedLot)return;
    setBusy(true);
    const today=new Date().toISOString().slice(0,10);
    const updated={...selectedLot,[type==='Riego'?'last_irrigation':'last_cut']:today,next_task:type==='Riego'?'Controlar humedad luego del riego':'Registrar producción del corte'};
    const next=lots.map(l=>l.id===updated.id?updated:l);
    onLotsChange?.(next);
    try{globalThis.localStorage.setItem(LOCAL_LOTS_KEY,JSON.stringify(next))}catch{}
    setBusy(false);setSelected(null);
    Alert.alert('Registro guardado',`${type} registrado hoy para ${selectedLot.name}.`);
  }
  return <>
    <View style={styles.infoBox}><Text style={styles.infoBoxTitle}>Gemelo digital · 1.1</Text><Text style={styles.muted}>Mapa real navegable: hacé zoom, desplazate, cambiá la capa y tocá cualquier válvula para operar sobre ella.</Text></View>
    <View style={styles.mapCardLarge}>
      <MapView ref={mapRef} style={styles.map} initialRegion={{...FARM_CENTER,latitudeDelta:0.020,longitudeDelta:0.018}} mapType={mapType} showsCompass showsScale rotateEnabled pitchEnabled>
        {features.map((f,i)=>{const c=colorFor(f);return <Polygon key={`${f.lot_id}-${i}`} coordinates={f.coordinates} tappable onPress={()=>setSelected(f)} strokeColor={c.stroke} fillColor={c.fill} strokeWidth={3}/>})}
        {showLabels&&features.map((f,i)=>{const c=f.center||f.coordinates?.[0];return c?<Marker key={`m-${f.lot_id}-${i}`} coordinate={c} onPress={()=>setSelected(f)}><View style={styles.mapLabel}><Text style={styles.mapLabelText}>{String(f.name||i+1).replace('Válvula ','V')}</Text></View></Marker>:null})}
      </MapView>
      <View style={styles.mapToolbar}>
        <Pressable style={styles.mapTool} onPress={fitFarm}><Text style={styles.mapToolIcon}>⌖</Text><Text style={styles.mapToolText}>Centrar</Text></Pressable>
        <Pressable style={styles.mapTool} onPress={()=>setShowLabels(v=>!v)}><Text style={styles.mapToolIcon}>{showLabels?'◉':'○'}</Text><Text style={styles.mapToolText}>Rótulos</Text></Pressable>
      </View>
      <View style={styles.layerPicker}>{[['satellite','Satélite'],['hybrid','Híbrido'],['standard','Mapa']].map(([key,label])=><Pressable key={key} onPress={()=>setMapType(key)} style={[styles.layerChip,mapType===key&&styles.layerChipActive]}><Text style={[styles.layerChipText,mapType===key&&styles.layerChipTextActive]}>{label}</Text></Pressable>)}</View>
    </View>
    <View style={styles.mapLegend}><View style={styles.legendItem}><View style={[styles.legendDot,{backgroundColor:'#07513d'}]}/><Text style={styles.legendText}>Alfalfa</Text></View><View style={styles.legendItem}><View style={[styles.legendDot,{backgroundColor:'#a47512'}]}/><Text style={styles.legendText}>Trigo</Text></View><View style={styles.legendItem}><View style={[styles.legendDot,{backgroundColor:'#cc3f2d'}]}/><Text style={styles.legendText}>Alerta NDVI</Text></View></View>
    <View style={styles.mapActions}><Pressable style={styles.secondaryButton} onPress={()=>setShowImport(true)}><Text style={styles.secondaryButtonText}>Importar GeoJSON</Text></Pressable><Pressable style={styles.secondaryButton} onPress={resetMap}><Text style={styles.secondaryButtonText}>Restablecer</Text></Pressable></View>
    <Card title="Resumen geográfico"><Row label="Sectores" value={`${features.length} válvulas`}/><Row label="Superficie KML" value={`${totalArea.toFixed(1)} ha`}/><Row label="Ubicación" value="Santiago Temple"/></Card>
    <Modal visible={!!selected} transparent animationType="slide" onRequestClose={()=>setSelected(null)}><View style={styles.modalOverlay}><View style={styles.mapSheet}><View style={styles.sheetHandle}/><Text style={styles.kicker}>SECTOR SELECCIONADO</Text><Text style={styles.sheetTitle}>{selected?.name}</Text><Text style={styles.sheetSubtitle}>{selectedLot?.crop||'Cultivo sin cargar'} · {selected?.area_ha||'—'} ha según KML</Text><View style={styles.sheetMetrics}><SheetMetric label="NDVI" value={selectedLot?.ndvi==null?'—':Number(selectedLot.ndvi).toFixed(2)}/><SheetMetric label="Humedad" value={selectedLot?.soil_moisture==null?'—':`${selectedLot.soil_moisture}%`}/><SheetMetric label="Estado" value={selectedLot?.status||'—'}/></View><Row label="Último riego" value={selectedLot?.last_irrigation||'Sin registrar'}/><Row label="Último corte" value={selectedLot?.last_cut||'Sin registrar'}/><Row label="Próxima tarea" value={selectedLot?.next_task||'Completar ficha'}/><View style={styles.sheetActions}><Pressable style={styles.sheetAction} onPress={()=>quickRegister('Riego')} disabled={busy}><Text style={styles.sheetActionIcon}>💧</Text><Text style={styles.sheetActionText}>Registrar riego</Text></Pressable><Pressable style={styles.sheetAction} onPress={()=>quickRegister('Corte')} disabled={busy}><Text style={styles.sheetActionIcon}>✂️</Text><Text style={styles.sheetActionText}>Registrar corte</Text></Pressable></View><Pressable style={styles.primary} onPress={()=>setSelected(null)}><Text style={styles.primaryText}>Cerrar ficha</Text></Pressable></View></View></Modal>
    <Modal visible={showImport} transparent animationType="slide" onRequestClose={()=>setShowImport(false)}><KeyboardAvoidingView style={styles.modalOverlay} behavior={Platform.OS==='ios'?'padding':undefined}><View style={styles.editModalCard}><Text style={styles.kicker}>LÍMITES REALES</Text><Text style={styles.cardTitle}>Importar GeoJSON</Text><Text style={styles.muted}>Pegá un FeatureCollection con polígonos. Los nombres Válvula 1 a Válvula 13 se vinculan por orden con las fichas de lote.</Text><TextInput style={[styles.input,styles.geoInput]} multiline value={geoText} onChangeText={setGeoText} autoCapitalize="none" placeholder='{"type":"FeatureCollection","features":[...]}'/><View style={styles.modalButtons}><Pressable style={styles.secondaryButton} onPress={()=>setShowImport(false)}><Text style={styles.secondaryButtonText}>Cancelar</Text></Pressable><Pressable style={[styles.primary,{flex:1,marginTop:0}]} onPress={importGeo}><Text style={styles.primaryText}>Importar</Text></Pressable></View></View></KeyboardAvoidingView></Modal>
  </>
}
function SheetMetric({label,value}){return <View style={styles.sheetMetric}><Text style={styles.sheetMetricValue}>{value}</Text><Text style={styles.sheetMetricLabel}>{label}</Text></View>}

function Lots({lots,companyId,latestAnalysis,onLotsChange,onIrrigationsChange,syncMode,setSyncMode}){
  const [query,setQuery]=useState(''),[filter,setFilter]=useState('Todos'),[selected,setSelected]=useState(null),[showAction,setShowAction]=useState(false),[actionType,setActionType]=useState('Riego'),[actionNote,setActionNote]=useState(''),[busy,setBusy]=useState(false);
  const [showEdit,setShowEdit]=useState(false),[draft,setDraft]=useState({});
  const normalized=(lots.length?lots:DEMO_LOTS).map(l=>{const a=latestAnalysis(l.id);return {...l,ndvi:a?.ndvi_avg??l.ndvi??null,crop:l.crop||l.cultivo||'Sin cultivo',area_ha:Number(l.area_ha||l.hectares||0),status:l.status||l.state||'Activo',last_irrigation:l.last_irrigation||l.last_irrigation_date||'',next_task:l.next_task||'Completar ficha',variety:l.variety||'',sowing_date:l.sowing_date||'',last_cut:l.last_cut||'',soil_moisture:l.soil_moisture==null?null:Number(l.soil_moisture),notes:l.notes||''};});
  const filtered=normalized.filter(l=>String(l.name||'').toLowerCase().includes(query.toLowerCase())&&(filter==='Todos'||String(l.crop).toLowerCase()===filter.toLowerCase()));
  const total=normalized.reduce((sum,l)=>sum+l.area_ha,0),alerts=normalized.filter(l=>Number(l.ndvi)>0&&Number(l.ndvi)<.65).length;
  function persistLocal(next){onLotsChange(next);try{globalThis.localStorage.setItem(LOCAL_LOTS_KEY,JSON.stringify(next))}catch{}}
  async function persistLot(updated){
    const next=normalized.map(x=>x.id===updated.id?updated:x);persistLocal(next);
    if(String(updated.id).startsWith('demo-')){setSyncMode('local');return false}
    const payload={id:updated.id,company_id:companyId||null,name:updated.name,crop:updated.crop,area_ha:updated.area_ha,variety:updated.variety||null,status:updated.status||'Activo',sowing_date:updated.sowing_date||null,last_cut:updated.last_cut||null,last_irrigation:updated.last_irrigation||null,ndvi:updated.ndvi,soil_moisture:updated.soil_moisture,next_task:updated.next_task||null,notes:updated.notes||null,updated_at:new Date().toISOString()};
    try{const {error}=await supabase.from(TABLES.lots).upsert(payload);if(error)throw error;setSyncMode('cloud');return true}catch{setSyncMode('local');return false}
  }
  function openAction(type){setActionType(type);setActionNote('');setShowAction(true)}
  async function saveAction(){
    setBusy(true);const today=new Date().toISOString().slice(0,10);let updated={...selected};
    if(actionType==='Riego')updated.last_irrigation=today;
    if(actionType==='Corte')updated.last_cut=today;
    updated.next_task=actionNote||updated.next_task;
    await persistLot(updated);setSelected(updated);
    const event={id:`local-${Date.now()}`,lot_id:selected.id,company_id:companyId||null,event_date:today,event_type:actionType,notes:actionNote||null,created_at:new Date().toISOString()};
    if(actionType==='Riego'){
      let local=[];try{local=JSON.parse(globalThis.localStorage.getItem(LOCAL_IRRIGATION_KEY)||'[]')}catch{}
      const next=[event,...local];try{globalThis.localStorage.setItem(LOCAL_IRRIGATION_KEY,JSON.stringify(next))}catch{};onIrrigationsChange?.(next);
      try{await supabase.from(TABLES.irrigations).insert(event)}catch{}
    }
    setBusy(false);setShowAction(false);Alert.alert('Registro guardado',`${actionType} registrado para ${selected.name}.`)
  }
  function openEdit(){setDraft({...selected,area_ha:String(selected.area_ha??''),ndvi:selected.ndvi==null?'':String(selected.ndvi),soil_moisture:selected.soil_moisture==null?'':String(selected.soil_moisture)});setShowEdit(true)}
  async function saveEdit(){
    const updated={...draft,area_ha:Number(String(draft.area_ha).replace(',','.'))||0,ndvi:draft.ndvi===''?null:Number(String(draft.ndvi).replace(',','.')),soil_moisture:draft.soil_moisture===''?null:Number(String(draft.soil_moisture).replace(',','.'))};
    setBusy(true);const cloud=await persistLot(updated);setSelected(updated);setBusy(false);setShowEdit(false);Alert.alert('Ficha actualizada',cloud?'Guardada en Supabase y en el iPhone.':'Guardada permanentemente en este iPhone. Para sincronizarla entre equipos falta crear las tablas V16 en Supabase.');
  }
  if(selected)return <>
    <Pressable style={styles.backButton} onPress={()=>setSelected(null)}><Text style={styles.backText}>‹ Volver a lotes</Text></Pressable>
    <View style={styles.lotHero}><Text style={styles.heroKicker}>{selected.crop.toUpperCase()} · {selected.area_ha} HA</Text><Text style={styles.lotHeroTitle}>{selected.name}</Text><Text style={styles.heroText}>{selected.variety||'Variedad por cargar'}</Text><View style={styles.ndviRow}><View><Text style={styles.ndviLabel}>NDVI ACTUAL</Text><Text style={styles.ndviValue}>{selected.ndvi==null?'—':Number(selected.ndvi).toFixed(2)}</Text></View><View><Text style={styles.ndviLabel}>HUMEDAD</Text><Text style={styles.ndviValue}>{selected.soil_moisture==null?'—':selected.soil_moisture+'%'}</Text></View></View></View>
    <Card title="Ficha del lote"><Row label="Estado" value={selected.status}/><Row label="Fecha de siembra" value={selected.sowing_date||'Sin cargar'}/><Row label="Último corte" value={selected.last_cut||'Sin cargar'}/><Row label="Último riego" value={selected.last_irrigation||'Sin cargar'}/><Row label="Próxima tarea" value={selected.next_task||'Sin cargar'}/></Card>
    <Card title="Observaciones"><Text style={styles.taskText}>{selected.notes||'Sin observaciones cargadas.'}</Text></Card>
    <Card title="Acciones rápidas"><View style={styles.quickGrid}><Quick text="Editar ficha" onPress={openEdit}/><Quick text="Registrar riego" onPress={()=>openAction('Riego')}/><Quick text="Registrar corte" onPress={()=>openAction('Corte')}/><Quick text="Cargar NDVI" onPress={()=>openAction('NDVI')}/></View></Card>
    <Modal visible={showAction} transparent animationType="slide" onRequestClose={()=>setShowAction(false)}><View style={styles.modalOverlay}><View style={styles.modalCard}><Text style={styles.cardTitle}>{actionType} · {selected.name}</Text><Text style={styles.muted}>Agregá una observación para dejar registro de la tarea.</Text><TextInput style={[styles.input,styles.modalInput]} placeholder="Detalle u observación" multiline value={actionNote} onChangeText={setActionNote}/><View style={styles.modalButtons}><Pressable style={styles.secondaryButton} onPress={()=>setShowAction(false)}><Text style={styles.secondaryButtonText}>Cancelar</Text></Pressable><Pressable style={[styles.primary,{flex:1,marginTop:0}]} onPress={saveAction} disabled={busy}><Text style={styles.primaryText}>{busy?'Guardando…':'Guardar'}</Text></Pressable></View></View></View></Modal>
    <Modal visible={showEdit} transparent animationType="slide" onRequestClose={()=>setShowEdit(false)}><View style={styles.modalOverlay}><ScrollView style={styles.editModalCard} contentContainerStyle={{paddingBottom:30}}><Text style={styles.cardTitle}>Editar {selected.name}</Text><EditField label="Nombre" value={draft.name} onChangeText={v=>setDraft({...draft,name:v})}/><EditField label="Cultivo" value={draft.crop} onChangeText={v=>setDraft({...draft,crop:v})}/><EditField label="Superficie (ha)" value={draft.area_ha} keyboardType="decimal-pad" onChangeText={v=>setDraft({...draft,area_ha:v})}/><EditField label="Variedad" value={draft.variety} onChangeText={v=>setDraft({...draft,variety:v})}/><EditField label="Estado" value={draft.status} onChangeText={v=>setDraft({...draft,status:v})}/><EditField label="Fecha de siembra" value={draft.sowing_date} placeholder="AAAA-MM-DD" onChangeText={v=>setDraft({...draft,sowing_date:v})}/><EditField label="Último corte" value={draft.last_cut} placeholder="AAAA-MM-DD" onChangeText={v=>setDraft({...draft,last_cut:v})}/><EditField label="Último riego" value={draft.last_irrigation} placeholder="AAAA-MM-DD" onChangeText={v=>setDraft({...draft,last_irrigation:v})}/><EditField label="NDVI" value={draft.ndvi} keyboardType="decimal-pad" placeholder="0.00" onChangeText={v=>setDraft({...draft,ndvi:v})}/><EditField label="Humedad (%)" value={draft.soil_moisture} keyboardType="decimal-pad" onChangeText={v=>setDraft({...draft,soil_moisture:v})}/><EditField label="Próxima tarea" value={draft.next_task} onChangeText={v=>setDraft({...draft,next_task:v})}/><EditField label="Observaciones" value={draft.notes} multiline onChangeText={v=>setDraft({...draft,notes:v})}/><View style={styles.modalButtons}><Pressable style={styles.secondaryButton} onPress={()=>setShowEdit(false)}><Text style={styles.secondaryButtonText}>Cancelar</Text></Pressable><Pressable style={[styles.primary,{flex:1,marginTop:0}]} onPress={saveEdit} disabled={busy}><Text style={styles.primaryText}>{busy?'Guardando…':'Guardar cambios'}</Text></Pressable></View></ScrollView></View></Modal>
  </>;
  return <><View style={styles.sectionHeader}><View><Text style={styles.cardTitle}>Mis lotes</Text><Text style={styles.muted}>{normalized.length} lotes · {total.toFixed(1)} ha</Text></View><View style={[styles.badge,alerts>0&&styles.badgeBad]}><Text style={styles.badgeText}>{alerts} alertas</Text></View></View><View style={styles.infoBox}><Text style={styles.infoBoxTitle}>{syncMode==='cloud'?'Sincronización activa':'Guardado permanente en iPhone'}</Text><Text style={styles.muted}>{syncMode==='cloud'?'Los cambios se guardan en Supabase y quedan disponibles para otros equipos.':'Los cambios no se pierden al cerrar la app. Incluimos el archivo CONFIGURAR_SUPABASE_V16.sql para activar la sincronización en la nube.'}</Text></View><TextInput style={styles.searchInput} placeholder="Buscar lote…" value={query} onChangeText={setQuery}/><ScrollView horizontal showsHorizontalScrollIndicator={false} style={{marginBottom:12}}>{['Todos','Alfalfa','Trigo'].map(x=><Pressable key={x} onPress={()=>setFilter(x)} style={[styles.filterChip,filter===x&&styles.filterChipActive]}><Text style={[styles.filterText,filter===x&&styles.filterTextActive]}>{x}</Text></Pressable>)}</ScrollView><View style={styles.summaryStrip}><MiniMetric label="Lotes" value={normalized.length}/><MiniMetric label="Superficie" value={`${total.toFixed(0)} ha`}/><MiniMetric label="Alfalfa" value={`${normalized.filter(x=>x.crop==='Alfalfa').reduce((sum,x)=>sum+x.area_ha,0)} ha`}/><MiniMetric label="Trigo" value={`${normalized.filter(x=>x.crop==='Trigo').reduce((sum,x)=>sum+x.area_ha,0)} ha`}/></View><Card title="Listado">{filtered.map(item=>{const warning=Number(item.ndvi)>0&&Number(item.ndvi)<.65;return <Pressable style={styles.lotItem} key={item.id} onPress={()=>setSelected(item)}><View style={{flex:1}}><View style={styles.lotTitleRow}><Text style={styles.itemTitle}>{item.name||'Lote'}</Text><Text style={styles.chevron}>›</Text></View><Text style={styles.muted}>{item.crop} · {item.area_ha} ha</Text><Text style={styles.lotTask}>{item.next_task||'Completar ficha'}</Text></View><View style={[styles.ndviBadge,warning&&styles.ndviBadgeWarn]}><Text style={styles.ndviBadgeLabel}>NDVI</Text><Text style={styles.ndviBadgeValue}>{item.ndvi==null?'—':Number(item.ndvi).toFixed(2)}</Text></View></Pressable>})}{!filtered.length&&<Empty text="No encontramos lotes con ese filtro."/>}</Card></>;
}
function EditField({label,multiline=false,...props}){return <View style={{marginTop:12}}><Text style={styles.label}>{label}</Text><TextInput style={[styles.input,multiline&&styles.modalInput]} multiline={multiline} {...props}/></View>}

function Irrigation({lots,irrigations,weather}){const eto=Number(weather?.daily?.et0_fao_evapotranspiration?.[0]||4.8),rain=Number(weather?.daily?.precipitation_sum?.slice(0,3).reduce((a,b)=>a+Number(b||0),0)||0);return <><Card title="Balance hídrico"><Row label="ET₀ de hoy" value={`${eto.toFixed(1)} mm`}/><Row label="Lluvia próxima (3 días)" value={`${rain.toFixed(1)} mm`}/></Card><Card title="Recomendaciones por lote">{lots.map(l=>{const last=irrigations.find(x=>x.lot_id===l.id),days=daysSince(last?.event_date||last?.irrigation_date),deficit=Math.max(0,days*eto-rain),hours=deficit/4;const priority=deficit>25?'Urgente':deficit>15?'Alta':deficit>7?'Media':'Correcto';return <View style={styles.listItem} key={l.id}><View style={{flex:1}}><Text style={styles.itemTitle}>{l.name||'Lote'}</Text><Text style={styles.muted}>{days} días desde el último riego · déficit {deficit.toFixed(1)} mm</Text></View><View style={[styles.badge,priority==='Urgente'&&styles.badgeBad]}><Text style={styles.badgeText}>{priority} · {hours.toFixed(1)} h</Text></View></View>})}</Card></>}
function Weather({weather}){if(!weather)return <Card title="Clima"><Empty text="No se pudo cargar el pronóstico."/></Card>;const d=weather.daily;return <><Card title="Condiciones actuales"><Row label="Temperatura" value={`${weather.current.temperature_2m} °C`}/><Row label="Humedad" value={`${weather.current.relative_humidity_2m} %`}/><Row label="Viento" value={`${weather.current.wind_speed_10m} km/h`}/></Card><Card title="Próximos 7 días">{d.time.map((date,i)=><View style={styles.listItem} key={date}><Text style={styles.itemTitle}>{new Date(`${date}T12:00:00`).toLocaleDateString('es-AR',{weekday:'short',day:'2-digit'})}</Text><Text style={styles.muted}>Lluvia {Number(d.precipitation_sum[i]||0).toFixed(1)} mm · ET₀ {Number(d.et0_fao_evapotranspiration[i]||0).toFixed(1)} mm</Text></View>)}</Card></>}

function Operations({lots,clients,operations,onChange}){
  const [section,setSection]=useState('Alfalfa'),[show,setShow]=useState(false),[draft,setDraft]=useState({});
  const sections=['Alfalfa','Maquinaria','Scania','Drones','Inventario','Economía','Equipo'];
  const current=operations.filter(x=>x.type===section);
  const rolls=operations.filter(x=>x.type==='Alfalfa').reduce((a,x)=>a+Number(x.quantity||0),0);
  const kilos=rolls*500;
  const income=operations.filter(x=>x.type==='Scania'||x.type==='Economía').reduce((a,x)=>a+Number(x.income||0),0);
  const cost=operations.filter(x=>x.type==='Scania'||x.type==='Economía').reduce((a,x)=>a+Number(x.cost||0),0);
  const lowStock=operations.filter(x=>x.type==='Inventario'&&Number(x.stock||0)<=Number(x.minimum||0)).length;
  function open(){setDraft({date:new Date().toISOString().slice(0,10),lot:lots[0]?.name||'',machine:'',hours:'',fuel:'',quantity:'',client:clients[0]?.name||'',destination:'',km:'',tons:'',income:'',cost:'',service:'Aplicación',hectares:'',product:'',unit:'kg',stock:'',minimum:'',movement:'Ingreso',person:'',role:'Operario',email:'',notes:''});setShow(true)}
  function save(){const item={id:`op-${Date.now()}`,type:section,...draft,created_at:new Date().toISOString()};onChange([item,...operations]);setShow(false);Alert.alert('Registro guardado',`${section} actualizado en el iPhone.`)}
  function titleFor(x){
    if(section==='Alfalfa')return `${x.quantity||0} rollos · ${x.lot||'Sin lote'}`;
    if(section==='Maquinaria')return `${x.machine||'Equipo'} · ${x.hours||0} h`;
    if(section==='Scania')return `${x.destination||'Viaje'} · ${x.tons||0} t`;
    if(section==='Drones')return `${x.service||'Trabajo'} · ${x.hectares||0} ha`;
    if(section==='Inventario')return `${x.product||'Producto'} · ${x.stock||0} ${x.unit||''}`;
    if(section==='Economía')return `${x.concept||'Movimiento'} · ${money(Number(x.income||0)-Number(x.cost||0))}`;
    return `${x.person||'Usuario'} · ${x.role||'Rol'}`;
  }
  return <>
    <View style={styles.summaryStrip}><MiniMetric label="ROLLOS" value={rolls}/><MiniMetric label="KG ALFALFA" value={kilos.toLocaleString('es-AR')}/><MiniMetric label="MARGEN" value={money(income-cost)}/><MiniMetric label="STOCK BAJO" value={lowStock}/></View>
    <View style={styles.infoBox}><Text style={styles.infoBoxTitle}>Gestión multiárea</Text><Text style={styles.muted}>Producción, equipos, logística, inventario, economía y usuarios en una sola pantalla. Los registros quedan guardados en este iPhone.</Text></View>
    <ScrollView horizontal showsHorizontalScrollIndicator={false} style={{marginBottom:12}}>{sections.map(x=><Pressable key={x} onPress={()=>setSection(x)} style={[styles.filterChip,section===x&&styles.filterChipActive]}><Text style={[styles.filterText,section===x&&styles.filterTextActive]}>{x}</Text></Pressable>)}</ScrollView>
    {section==='Economía'&&<Card title="Resumen económico"><Row label="Ingresos registrados" value={money(income)}/><Row label="Costos registrados" value={money(cost)}/><Row label="Resultado" value={money(income-cost)}/></Card>}
    {section==='Inventario'&&<Card title="Alertas de stock"><Row label="Productos en mínimo" value={String(lowStock)}/><Text style={styles.muted}>Se considera alerta cuando el stock actual es igual o menor al mínimo cargado.</Text></Card>}
    <Card title={section}><Pressable style={styles.primary} onPress={open}><Text style={styles.primaryText}>+ Nuevo registro</Text></Pressable>{!current.length?<Empty text={`Todavía no hay registros de ${section.toLowerCase()}.`}/>:current.map(x=><View key={x.id} style={styles.listItem}><View style={{flex:1}}><Text style={styles.itemTitle}>{titleFor(x)}</Text><Text style={styles.muted}>{x.date||''}{x.notes?` · ${x.notes}`:''}</Text></View>{section==='Inventario'&&Number(x.stock||0)<=Number(x.minimum||0)&&<View style={[styles.badge,styles.badgeBad]}><Text style={styles.badgeText}>Reponer</Text></View>}</View>)}</Card>
    <Modal visible={show} transparent animationType="slide" onRequestClose={()=>setShow(false)}><KeyboardAvoidingView style={styles.modalOverlay} behavior={Platform.OS==='ios'?'padding':undefined}><ScrollView style={styles.editModalCard}><Text style={styles.cardTitle}>Nuevo registro · {section}</Text><EditField label="Fecha" value={draft.date||''} onChangeText={v=>setDraft({...draft,date:v})}/>{section==='Alfalfa'&&<><EditField label="Lote" value={draft.lot||''} onChangeText={v=>setDraft({...draft,lot:v})}/><EditField label="Cantidad de rollos" keyboardType="decimal-pad" value={draft.quantity||''} onChangeText={v=>setDraft({...draft,quantity:v})}/></>}{section==='Maquinaria'&&<><EditField label="Máquina o implemento" value={draft.machine||''} onChangeText={v=>setDraft({...draft,machine:v})}/><EditField label="Horas trabajadas" keyboardType="decimal-pad" value={draft.hours||''} onChangeText={v=>setDraft({...draft,hours:v})}/><EditField label="Combustible (litros)" keyboardType="decimal-pad" value={draft.fuel||''} onChangeText={v=>setDraft({...draft,fuel:v})}/></>}{section==='Scania'&&<><EditField label="Cliente" value={draft.client||''} onChangeText={v=>setDraft({...draft,client:v})}/><EditField label="Destino" value={draft.destination||''} onChangeText={v=>setDraft({...draft,destination:v})}/><EditField label="Kilómetros" keyboardType="decimal-pad" value={draft.km||''} onChangeText={v=>setDraft({...draft,km:v})}/><EditField label="Toneladas" keyboardType="decimal-pad" value={draft.tons||''} onChangeText={v=>setDraft({...draft,tons:v})}/><EditField label="Ingreso ($)" keyboardType="decimal-pad" value={draft.income||''} onChangeText={v=>setDraft({...draft,income:v})}/><EditField label="Costo ($)" keyboardType="decimal-pad" value={draft.cost||''} onChangeText={v=>setDraft({...draft,cost:v})}/></>}{section==='Drones'&&<><EditField label="Servicio" value={draft.service||''} onChangeText={v=>setDraft({...draft,service:v})}/><EditField label="Cliente" value={draft.client||''} onChangeText={v=>setDraft({...draft,client:v})}/><EditField label="Hectáreas" keyboardType="decimal-pad" value={draft.hectares||''} onChangeText={v=>setDraft({...draft,hectares:v})}/></>}{section==='Inventario'&&<><EditField label="Producto" value={draft.product||''} onChangeText={v=>setDraft({...draft,product:v})}/><EditField label="Unidad" value={draft.unit||''} onChangeText={v=>setDraft({...draft,unit:v})}/><EditField label="Stock actual" keyboardType="decimal-pad" value={draft.stock||''} onChangeText={v=>setDraft({...draft,stock:v})}/><EditField label="Stock mínimo" keyboardType="decimal-pad" value={draft.minimum||''} onChangeText={v=>setDraft({...draft,minimum:v})}/><EditField label="Movimiento" value={draft.movement||''} onChangeText={v=>setDraft({...draft,movement:v})}/></>}{section==='Economía'&&<><EditField label="Concepto" value={draft.concept||''} onChangeText={v=>setDraft({...draft,concept:v})}/><EditField label="Ingreso ($)" keyboardType="decimal-pad" value={draft.income||''} onChangeText={v=>setDraft({...draft,income:v})}/><EditField label="Costo ($)" keyboardType="decimal-pad" value={draft.cost||''} onChangeText={v=>setDraft({...draft,cost:v})}/><EditField label="Lote / centro de costo" value={draft.lot||''} onChangeText={v=>setDraft({...draft,lot:v})}/></>}{section==='Equipo'&&<><EditField label="Nombre" value={draft.person||''} onChangeText={v=>setDraft({...draft,person:v})}/><EditField label="Rol" value={draft.role||''} onChangeText={v=>setDraft({...draft,role:v})}/><EditField label="Correo" keyboardType="email-address" autoCapitalize="none" value={draft.email||''} onChangeText={v=>setDraft({...draft,email:v})}/></>}<EditField label="Observaciones" multiline value={draft.notes||''} onChangeText={v=>setDraft({...draft,notes:v})}/><View style={styles.modalButtons}><Pressable style={styles.secondaryButton} onPress={()=>setShow(false)}><Text style={styles.secondaryButtonText}>Cancelar</Text></Pressable><Pressable style={[styles.primary,{flex:1,marginTop:0}]} onPress={save}><Text style={styles.primaryText}>Guardar</Text></Pressable></View><View style={{height:30}}/></ScrollView></KeyboardAvoidingView></Modal>
  </>
}

function Clients({clients}){return <Card title="Clientes"><FlatList scrollEnabled={false} data={clients} keyExtractor={(x,i)=>String(x.id||i)} ListEmptyComponent={<Empty text="Todavía no hay clientes cargados."/>} renderItem={({item})=><View style={styles.listItem}><View><Text style={styles.itemTitle}>{item.name||item.client_name||'Cliente'}</Text><Text style={styles.muted}>{item.phone||item.whatsapp||'Sin teléfono'} · {item.location||'Sin ubicación'}</Text></View></View>}/></Card>}
function MiniMetric({label,value}){return <View style={styles.miniMetric}><Text style={styles.miniMetricValue}>{value}</Text><Text style={styles.miniMetricLabel}>{label}</Text></View>}
function Metric({label,value,sub}){return <View style={styles.metric}><Text style={styles.metricLabel}>{label}</Text><Text style={styles.metricValue}>{value}</Text><Text style={styles.metricSub}>{sub}</Text></View>}
function Card({title,children}){return <View style={styles.card}><Text style={styles.cardTitle}>{title}</Text>{children}</View>}
function Row({label,value}){return <View style={styles.row}><Text style={styles.rowLabel}>{label}</Text><Text style={styles.rowValue}>{value}</Text></View>}
function Quick({text,onPress}){return <Pressable style={styles.quick} onPress={onPress}><Text style={styles.quickText}>{text}</Text></Pressable>}
function Empty({text}){return <Text style={[styles.muted,{textAlign:'center',padding:24}]}>{text}</Text>}
function Centered({children}){return <SafeAreaView style={styles.centered}>{children}</SafeAreaView>}

